using System.Net.Http.Json;
using System.Text.Json;
using System.Text.Json.Serialization;
using ModelContextProtocol.Server;

namespace McpRestServer;

[McpServerToolType]
public sealed class WeatherTools
{
    private readonly IHttpClientFactory _httpClientFactory;

    // Constructor parameters are resolved from DI automatically.
    public WeatherTools(IHttpClientFactory httpClientFactory)
    {
        _httpClientFactory = httpClientFactory;
    }

    [McpServerTool(Name = "get_weather"),
     Description("Get current weather for a location by latitude and longitude.")]
    public async Task<string> GetWeatherAsync(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude)
    {
        var client = _httpClientFactory.CreateClient("WeatherApi");
        var url = $"v1/forecast?latitude={latitude}&longitude={longitude}"
                + "&current=temperature_2m,wind_speed_10m";

        var response = await client.GetFromJsonAsync<JsonElement>(url);

        var current = response.GetProperty("current");
        var temp = current.GetProperty("temperature_2m").GetDouble();
        var wind = current.GetProperty("wind_speed_10m").GetDouble();
        var units = response.GetProperty("current_units");
        var tempUnit = units.GetProperty("temperature_2m").GetString();
        var windUnit = units.GetProperty("wind_speed_10m").GetString();

        return $"Temperature: {temp}{tempUnit}, Wind: {wind} {windUnit}";
    }

    [McpServerTool(Name = "get_forecast"),
     Description("Get a multi-day temperature forecast for a location.")]
    public async Task<string> GetForecastAsync(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude,
        [Description("Number of forecast days (1-16)")] int days = 7)
    {
        days = Math.Clamp(days, 1, 16);
        var client = _httpClientFactory.CreateClient("WeatherApi");
        var url = $"v1/forecast?latitude={latitude}&longitude={longitude}"
                + $"&daily=temperature_2m_max,temperature_2m_min&forecast_days={days}";

        var response = await client.GetFromJsonAsync<JsonElement>(url);

        var daily = response.GetProperty("daily");
        var dates = daily.GetProperty("time").EnumerateArray().Select(e => e.GetString()).ToList();
        var maxTemps = daily.GetProperty("temperature_2m_max").EnumerateArray().Select(e => e.GetDouble()).ToList();
        var minTemps = daily.GetProperty("temperature_2m_min").EnumerateArray().Select(e => e.GetDouble()).ToList();

        var lines = dates.Select((date, i) =>
            $"{date}: {minTemps[i]}°C – {maxTemps[i]}°C");

        return string.Join("\n", lines);
    }
}

